'use client'
// app/dashboard/layout.tsx
import { useEffect, useState } from 'react'
import { useRouter, usePathname } from 'next/navigation'
import { createClient } from '@/lib/supabase'
import { AppUser } from '@/types'

export default function DashboardLayout({ children }: { children: React.ReactNode }) {
  const router = useRouter()
  const pathname = usePathname()
  const supabase = createClient()
  const [user, setUser] = useState<AppUser | null>(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    async function load() {
      const { data: { session } } = await supabase.auth.getSession()
      if (!session) { router.push('/auth'); return }
      const { data } = await supabase.from('app_users').select('*').eq('id', session.user.id).single()
      if (!data) { router.push('/auth'); return }
      setUser(data); setLoading(false)
    }
    load()
  }, [])

  async function handleLogout() {
    await supabase.auth.signOut()
    router.push('/auth')
  }

  if (loading) return (
    <div className="min-h-screen flex items-center justify-center" style={{background:'#1A1A1A'}}>
      <div className="text-center">
        <div className="w-12 h-12 rounded-xl flex items-center justify-center text-2xl mx-auto mb-3" style={{background:'#FFD600'}}>🔧</div>
        <p className="text-white text-sm font-bold tracking-widest uppercase opacity-60">Loading…</p>
      </div>
    </div>
  )

  const isMaster = user?.role === 'master'
  const isClient = user?.role === 'client'

  const navItems = [
    { href: '/dashboard', label: 'Job Board', icon: '📋', show: true },
    { href: '/dashboard/overview', label: 'Overview', icon: '📊', show: !isClient },
    { href: '/dashboard/reminders', label: 'Reminders', icon: '🔔', show: !isClient },
    { href: '/dashboard/settings', label: 'Settings', icon: '⚙️', show: isMaster },
  ].filter(n => n.show)

  return (
    <div className="flex flex-col min-h-screen">
      {/* Header */}
      <header className="sticky top-0 z-50 flex items-center justify-between px-6 h-15"
        style={{background:'#1A1A1A',height:'60px',boxShadow:'0 2px 10px rgba(0,0,0,.2)'}}>
        <div className="flex items-center gap-3">
          <img src="data:image/svg+xml;base64," alt="MR DIY" style={{width:'36px',height:'36px',objectFit:'contain',borderRadius:'6px',background:'#FFD600',padding:'2px'}} />
          <div>
            <div className="font-extrabold text-white text-lg leading-none" style={{fontFamily:'"Black Han Sans",sans-serif',letterSpacing:'1px'}}>MR.DIY</div>
            <div className="text-xs font-bold tracking-widest uppercase leading-none" style={{color:'rgba(255,255,255,.35)'}}>Job Tracker</div>
          </div>
        </div>
        <div className="flex items-center gap-3">
          {!isClient && (
            <button onClick={() => router.push('/dashboard/reminders')}
              className="hidden md:flex items-center gap-2 px-3 py-2 rounded-lg text-white text-xs font-bold"
              style={{background:'rgba(255,255,255,.1)',border:'1px solid rgba(255,255,255,.15)'}}>
              🔔 Reminders
            </button>
          )}
          <div className="flex items-center gap-2 px-3 py-2 rounded-lg" style={{background:'rgba(255,255,255,.07)'}}>
            <div className="w-8 h-8 rounded-lg flex items-center justify-center font-extrabold text-sm" style={{background:'#FFD600',color:'#000'}}>
              {user?.name.charAt(0).toUpperCase()}
            </div>
            <div>
              <div className="text-white text-sm font-bold leading-none">{user?.name}</div>
              <div className="text-xs font-extrabold tracking-widest uppercase leading-none mt-1" style={{color:'#FFD600'}}>{user?.role}</div>
            </div>
          </div>
          <button onClick={handleLogout}
            className="hidden md:block px-3 py-2 rounded-lg text-xs font-bold tracking-wide transition-all"
            style={{background:'transparent',border:'1px solid rgba(255,255,255,.18)',color:'rgba(255,255,255,.55)'}}>
            Sign Out
          </button>
        </div>
      </header>

      <div className="flex flex-1">
        {/* Sidebar */}
        <aside className="hidden md:block w-56 flex-shrink-0 sticky top-15 h-screen overflow-y-auto py-5"
          style={{top:'60px',height:'calc(100vh - 60px)',background:'#fff',borderRight:'1.5px solid #E2DFD3'}}>
          <div className="px-3">
            <p className="text-xs font-extrabold tracking-widest uppercase mb-3 px-2" style={{color:'#888880'}}>Navigation</p>
            {navItems.map(n => (
              <button key={n.href} onClick={() => router.push(n.href)}
                className="w-full flex items-center gap-2 px-3 py-2 rounded-lg text-sm font-bold mb-1 transition-all text-left"
                style={{
                  background: pathname === n.href ? '#1A1A1A' : 'transparent',
                  color: pathname === n.href ? '#fff' : '#3A3A38',
                  border: '1.5px solid transparent',
                }}>
                <span className="text-base w-5 text-center">{n.icon}</span>
                {n.label}
              </button>
            ))}
          </div>
        </aside>

        {/* Main */}
        <main className="flex-1 overflow-x-auto flex flex-col" style={{background:'#F7F6F2'}}>
          <div className="flex-1 p-3 md:p-6 pb-20 md:pb-6">{children}</div>
          <footer className="hidden md:block text-center py-3 px-6" style={{borderTop:'1px solid #E2DFD3',background:'#fff'}}>
            <p style={{fontSize:'10px',fontFamily:'"Barlow Condensed",sans-serif',fontWeight:600,letterSpacing:'.5px',color:'#888880'}}>
              This system is the proprietary technology of C&amp;C Creative Consultancy Sdn Bhd. Unauthorized use or reproduction is prohibited.
            </p>
          </footer>
        </main>
      </div>

      {/* Mobile Bottom Nav */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 z-50 flex items-center justify-around px-2 py-2"
        style={{background:'#1A1A1A',borderTop:'2px solid #FFD600',height:'60px'}}>
        {navItems.map(n => (
          <button key={n.href} onClick={() => router.push(n.href)}
            className="flex flex-col items-center gap-0.5 px-3 py-1 rounded-lg flex-1"
            style={{color: pathname === n.href ? '#FFD600' : 'rgba(255,255,255,.5)'}}>
            <span className="text-lg leading-none">{n.icon}</span>
            <span className="text-xs font-bold tracking-wide" style={{fontSize:'10px'}}>{n.label}</span>
          </button>
        ))}
        <button onClick={handleLogout}
          className="flex flex-col items-center gap-0.5 px-3 py-1 rounded-lg flex-1"
          style={{color:'rgba(255,255,255,.5)'}}>
          <span className="text-lg leading-none">🚪</span>
          <span className="text-xs font-bold tracking-wide" style={{fontSize:'10px'}}>Sign Out</span>
        </button>
      </nav>
    </div>
  )
}
